import { AfterViewChecked, Component, OnDestroy } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface Todo {
  id: number;
  text: string;
  done: boolean;
}

type Filter = 'all' | 'active' | 'completed';

interface PendingUndo {
  item: Todo;
  index: number;
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy, AfterViewChecked {
  newTask = '';
  todos: Todo[] = [];
  filter: Filter = 'all';
  editingId: number | null = null;
  editDraft = '';
  pendingUndo: PendingUndo | null = null;
  liveMessage = '';
  private nextId = 1;
  private undoTimerId: number | null = null;
  private pendingFocus: { selector: string; select: boolean } | null = null;

  get visibleTodos(): Todo[] {
    if (this.filter === 'active') return this.todos.filter((todo) => !todo.done);
    if (this.filter === 'completed') return this.todos.filter((todo) => todo.done);
    return this.todos;
  }

  get remainingLabel(): string {
    const count = this.todos.filter((todo) => !todo.done).length;
    return count === 1 ? '1 item left' : count + ' items left';
  }

  get hasCompleted(): boolean {
    return this.todos.some((todo) => todo.done);
  }

  addTask(): void {
    const normalizedTask = this.newTask.trim();
    if (!normalizedTask) return;
    this.todos = [
      ...this.todos,
      { id: this.nextId++, text: normalizedTask, done: false }
    ];
    this.newTask = '';
    this.liveMessage = 'Added ' + normalizedTask + '.';
  }

  toggleTask(taskId: number): void {
    this.todos = this.todos.map((todo) => (
      todo.id === taskId ? { ...todo, done: !todo.done } : todo
    ));
  }

  setFilter(nextFilter: Filter): void {
    this.filter = nextFilter;
  }

  startEditing(todo: Todo): void {
    this.editingId = todo.id;
    this.editDraft = todo.text;
    this.pendingFocus = { selector: '.edit-input', select: true };
  }

  finishEditing(saveChanges: boolean): void {
    if (this.editingId === null) return;
    const taskId = this.editingId;
    const normalizedDraft = this.editDraft.trim();
    if (saveChanges && normalizedDraft) {
      this.todos = this.todos.map((todo) => (
        todo.id === taskId ? { ...todo, text: normalizedDraft } : todo
      ));
      this.liveMessage = 'Updated task to ' + normalizedDraft + '.';
    }
    this.editingId = null;
    this.editDraft = '';
    this.pendingFocus = {
      selector: '.edit-task[data-id="' + taskId + '"]',
      select: false
    };
  }

  onEditKeydown(event: KeyboardEvent): void {
    if (event.key === 'Enter') {
      event.preventDefault();
      this.finishEditing(true);
    } else if (event.key === 'Escape') {
      event.preventDefault();
      this.finishEditing(false);
    }
  }

  removeTask(taskId: number): void {
    const removedIndex = this.todos.findIndex((todo) => todo.id === taskId);
    if (removedIndex < 0) return;
    const removedTodo = this.todos[removedIndex];
    this.clearUndoTimer();
    this.todos = this.todos.filter((todo) => todo.id !== taskId);
    this.pendingUndo = { item: removedTodo, index: removedIndex };
    this.liveMessage = 'Removed ' + removedTodo.text + '. Undo available for 5 seconds.';
    this.undoTimerId = window.setTimeout(() => {
      this.undoTimerId = null;
      this.pendingUndo = null;
      this.liveMessage = 'Undo expired for ' + removedTodo.text + '.';
    }, 5000);
  }

  undoRemoval(): void {
    if (!this.pendingUndo) return;
    const snapshot = this.pendingUndo;
    this.clearUndoTimer();
    if (!this.todos.some((todo) => todo.id === snapshot.item.id)) {
      const restoredTodos = [...this.todos];
      restoredTodos.splice(
        Math.min(snapshot.index, restoredTodos.length),
        0,
        snapshot.item
      );
      this.todos = restoredTodos;
    }
    this.pendingUndo = null;
    this.liveMessage = 'Restored ' + snapshot.item.text + '.';
  }

  clearCompleted(): void {
    this.todos = this.todos.filter((todo) => !todo.done);
    this.liveMessage = 'Cleared completed tasks.';
  }

  ngAfterViewChecked(): void {
    const pending = this.pendingFocus;
    if (!pending) return;
    this.pendingFocus = null;
    queueMicrotask(() => {
      const control = document.querySelector<HTMLElement & { select?: () => void }>(
        pending.selector
      );
      control?.focus();
      if (pending.select) control?.select?.();
    });
  }

  private clearUndoTimer(): void {
    if (this.undoTimerId !== null) {
      window.clearTimeout(this.undoTimerId);
      this.undoTimerId = null;
    }
  }

  ngOnDestroy(): void {
    this.clearUndoTimer();
  }
}
